public interface ShippingStrategy {
    double calculate(double weight);
}

public class StandardShipping implements ShippingStrategy {
    private static final double RATE = 2.5;

    @Override
    public double calculate(double weight) {
        return weight * RATE;
    }
}

public class ExpressShipping implements ShippingStrategy {
    private static final double RATE = 5.0;
    private static final double FLAT_FEE = 10.0;

    @Override
    public double calculate(double weight) {
        return weight * RATE + FLAT_FEE;
    }
}

public class SameDayShipping implements ShippingStrategy {
    private static final double RATE = 10.0;
    private static final double FLAT_FEE = 25.0;

    @Override
    public double calculate(double weight) {
        return weight * RATE + FLAT_FEE;
    }
}

public class ShippingCalculator {
    private final Map<String, ShippingStrategy> strategies = new HashMap<>();

    public ShippingCalculator() {
        strategies.put("STANDARD", new StandardShipping());
        strategies.put("EXPRESS", new ExpressShipping());
        strategies.put("SAME_DAY", new SameDayShipping());
    }

    public double calculateShipping(String type, double weight) {
        ShippingStrategy strategy = strategies.get(type);
        if (strategy == null) {
            throw new IllegalArgumentException("Bilinmeyen kargo tipi: " + type);
        }
        return strategy.calculate(weight);
    }
}

