    lastName: string;
    email: string;
    age: number;
}

interface ProcessedUser {
    fullName: string;
    email: string;
    isAdult: boolean;
}

function isValidUser(user: RawUser): boolean {
    return !!user.email
        && user.email.includes('@')
        && user.age >= 18;
}

function toProcessedUser(user: RawUser): ProcessedUser {
    return {
        fullName: `${user.firstName} ${user.lastName}`,
        email: user.email.toLowerCase(),
        isAdult: true,
    };
}

function processUserData(users: RawUser[]): ProcessedUser[] {
    return users
        .filter(isValidUser)
        .map(toProcessedUser);
}

