package main

type Employee struct {
	Name       string
	Age        int
	Department string
	Salary     float64
	Email      string
	Phone      string
}

type EmployeeOption func(*Employee)

func NewEmployee(name string, opts ...EmployeeOption) *Employee {
	e := &Employee{Name: name}
	for _, opt := range opts {
		opt(e)
	}
	return e
}

func WithAge(age int) EmployeeOption {
	return func(e *Employee) {
		e.Age = age
	}
}

func WithDepartment(dept string) EmployeeOption {
	return func(e *Employee) {
		e.Department = dept
	}
}

func WithSalary(salary float64) EmployeeOption {
	return func(e *Employee) {
		e.Salary = salary
	}
}

